import { connect, useDispatch } from 'react-redux';

import cls from './Company.module.scss';
import { useEffect, useState } from 'react';
import { setMessageBar, setShowMenu, setShowSideMenu } from '../../../reduxStore/actions/flowActions';
import { uncachedUrl } from '../../../shared/utility';
import { useNavigate, useParams } from 'react-router-dom';
import { getCompanyDetailsUsingSlug } from '../../../services/company.service';
import { first } from 'rxjs';
import { isMobile } from 'react-device-detect';


const CompanyHome = props => {
	const dispatch = useDispatch();
	const [companyData, setCompanyData] = useState(JSON.parse(localStorage.getItem('companyData')) ?? { 'name': '' });
	const { slug } = useParams();
	const navigate = useNavigate();
	document.title = `Company | ${slug}`;

	useEffect(() => {

		if (!companyData?.display_name || slug !== companyData?.slug) {
			dispatch(setShowSideMenu(false));
			dispatch(setShowMenu(false));
			getCompanyDetailsUsingSlug(slug)
				.pipe(first())
				.subscribe({
					next: data => {
						dispatch(setMessageBar({ show: false, message: '' }));
						localStorage.setItem('companyData', JSON.stringify(data));
						setCompanyData(data);
					},
				});
		}
	}, [companyData]);

	return (
		<div
			className={cls.companyHome}
			style={{
				backgroundRepeat: 'no-repeat',
				height: isMobile ? '80vh' : '70vh',
				backgroundImage: companyData?.company_standards?.hbanner ? `url(${companyData?.company_standards?.hbanner})` : ``,
				backgroundColor: '#cccccc',
				backgroundSize: 'cover',
				backgroundPosition: 'center'
			}}
		>
			<div className={cls.navbarSection} style={{ padding: isMobile ? '0' : '', display: companyData.company_standards?.message ? 'flex' : 'flex', flexDirection: isMobile ? 'column' : 'row' }}>
				<div style={{ display: 'flex', margin: '20px', width: '100%', justifyContent: 'space-between' }}>

					<div style={{ display: 'flex', flexDirection: isMobile ? 'row' : 'row' }}>

						<div
							onClick={() => navigate('/login')}
							style={{
								cursor: 'pointer',
								fontFamily: 'var(--app-text-mobile-font)',
								fontSize: isMobile ? '18px' : '26px',
								color: '#4A4A4A',
								paddingLeft: isMobile ? '20px' : '20px',
								textUnderlineOffset: '6px'
							}}
						>
							{'Login'}
						</div>
						{companyData?.core_values?.singleUser && !isMobile && <div
							onClick={() => {
								dispatch(setMessageBar({ show: false, message: '' }));
								navigate('/user');
							}}
							style={{
								cursor: 'pointer',
								fontFamily: 'var(--app-text-mobile-font)',
								fontSize: '26px',
								color: '#4A4A4A',
								paddingLeft: isMobile ? '20px' : '20px',
								textUnderlineOffset: '6px'
							}}
						>
							{'Sign up'}
						</div>}
					</div>


					{!isMobile && companyData?.logo && <img alt="lg" src={uncachedUrl(companyData?.logo)} className={cls.logoUrlImg} />}

				</div>
			</div>

			{!companyData?.logo && companyData?.display_name ? <div className={cls.centerDiv} style={{ backgroundColor: 'white', fontSize: isMobile ? '' : '30px' }}>
				{companyData?.display_name}
			</div> : isMobile && <div className={cls.centerDiv} style={{ backgroundColor: 'transparent', fontSize: isMobile ? '' : '30px' }}>
				<img alt="lg" src={uncachedUrl(companyData?.logo)} className={cls.logoUrlImgM} />
			</div>


			}

			{!isMobile && companyData.company_standards?.message && <div className={cls.banner2}>{companyData.company_standards?.message}</div>}
			{!isMobile && companyData.company_standards?.subMessage && (
				<div className={cls.banner2} xstyle={{ backgroundColor: 'var(--app-color-blue)' }}>
					{companyData.company_standards?.subMessage}
				</div>
			)}
		</div>
	);
};

const mapStateToProps = store => {
	const {
		authenticatedUser: { position },
		authenticatedUser,
	} = store.authReducer;
	const { user } = store.sessionReducer;

	const { companyData, companyPositionsArray, allTasks, allCompletedTasks, allCompletedTasksPaginated, companyUsersArray } = store.flowReducer;
	return {
		companyData,
		companyPositionsArray,
		position,
		allTasks,
		allCompletedTasks,
		allCompletedTasksPaginated,
		user,
		companyUsersArray,
		authenticatedUser,
	};
};

const mapDispatchToProps = dispatch => {
	return {
		// onSetOnBoardingVisible: visible => dispatch(setOnBoardingVisible(visible)),
		// onToggleModalVisibility: modalVisible => dispatch(setOnBoardingModalsVisibility(modalVisible)),
	};
};
export default connect(mapStateToProps, mapDispatchToProps)(CompanyHome);
